INSERT INTO public.competitions (id, name, short_name, country, country_or_region, competition_type, type, region, priority, is_international, tier, data_source, source_file, seasons, team_count, is_active, is_featured, status, country_id, updated_at)
SELECT i.id, i.name, i.short_name, i.country, i.country_or_region, i.competition_type, i.type, i.region, i.priority, i.is_international, 1, i.data_source, i.source_file, i.seasons, i.team_count, i.is_active, i.is_featured, i.status, c.id, timezone('utc', now())
FROM incoming i LEFT JOIN public.countries c ON c.iso_code = i.country_code
ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, short_name = EXCLUDED.short_name, country = EXCLUDED.country, country_or_region = EXCLUDED.country_or_region, competition_type = EXCLUDED.competition_type, type = EXCLUDED.type, region = EXCLUDED.region, priority = EXCLUDED.priority, is_international = EXCLUDED.is_international, tier = EXCLUDED.tier, data_source = EXCLUDED.data_source, source_file = EXCLUDED.source_file, seasons = EXCLUDED.seasons, team_count = EXCLUDED.team_count, is_active = EXCLUDED.is_active, is_featured = EXCLUDED.is_featured, status = EXCLUDED.status, country_id = EXCLUDED.country_id, updated_at = timezone('utc', now());

