INSERT INTO public.teams (id, name, short_name, country, country_code, league_name, competition_ids, aliases, search_terms, is_active, is_featured, is_popular_pick, popular_pick_rank, region, team_type, country_id, popularity_score, updated_at)
SELECT i.id, i.name, i.short_name, i.country, i.country_code, i.league_name, i.competition_ids, i.aliases, i.search_terms, i.is_active, i.is_featured, i.is_popular_pick, i.popular_pick_rank::integer, i.region, i.team_type, c.id, i.popularity_score, timezone('utc', now())
FROM incoming i LEFT JOIN public.countries c ON c.iso_code = i.country_code
ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, short_name = EXCLUDED.short_name, country = EXCLUDED.country, country_code = EXCLUDED.country_code, league_name = EXCLUDED.league_name, competition_ids = EXCLUDED.competition_ids, aliases = EXCLUDED.aliases, search_terms = EXCLUDED.search_terms, is_active = EXCLUDED.is_active, is_featured = EXCLUDED.is_featured, is_popular_pick = EXCLUDED.is_popular_pick, popular_pick_rank = EXCLUDED.popular_pick_rank, region = EXCLUDED.region, team_type = EXCLUDED.team_type, country_id = EXCLUDED.country_id, popularity_score = EXCLUDED.popularity_score, updated_at = timezone('utc', now());

